import DOMPurify from "dompurify";
import { defaultBestOf } from "../state.js";
import { normalizeRoundRobinSettings } from "../bracket/build.js";
import { syncMarkdownSurfaceForInput } from "../markdownEditor.js";
import { formatLocalDateTimeInput } from "../dateTime.js";

const DEFAULT_PRIZE_SPLIT_ROWS = [
  { place: 1, amount: 50 },
  { place: 2, amount: 30 },
  { place: 3, amount: 20 },
];

function normalizePrizeSplitRows(value, total = null) {
  const raw = Array.isArray(value) ? value : [];
  const mapped = raw
    .map((row, idx) => {
      if (row && typeof row === "object") {
        const legacyPercent = Number(row.percent);
        const amountFromPercent =
          Number.isFinite(legacyPercent) &&
          legacyPercent >= 0 &&
          Number.isFinite(total) &&
          total > 0
            ? Math.round((total * legacyPercent) / 100)
            : NaN;
        return {
          place: Number(row.place),
          amount: Number(
            row.amount ??
              row.value ??
              row.points ??
              (Number.isFinite(amountFromPercent)
                ? amountFromPercent
                : row.percent) ??
              0,
          ),
        };
      }
      const amount = Number(row);
      return {
        place: idx + 1,
        amount,
      };
    })
    .filter(
      (row) =>
        Number.isFinite(row.place) &&
        row.place > 0 &&
        Number.isFinite(row.amount) &&
        row.amount >= 0,
    );
  const deduped = new Map();
  mapped.forEach((row) => {
    deduped.set(row.place, row.amount);
  });
  return Array.from(deduped.entries())
    .sort((a, b) => a[0] - b[0])
    .map(([place, amount]) => ({ place, amount }));
}

export function readPrizeSplitRows() {
  const rows = Array.from(
    document.querySelectorAll("#settingsPrizeSplitBody [data-prize-split-row]"),
  )
    .map((row) => ({
      place: Number(row.querySelector("[data-prize-place]")?.value),
      amount: Number(row.querySelector("[data-prize-amount]")?.value),
    }))
    .filter(
      (row) =>
        Number.isFinite(row.place) &&
        row.place > 0 &&
        Number.isFinite(row.amount) &&
        row.amount >= 0,
    );
  return normalizePrizeSplitRows(rows);
}

export function renderPrizeSplitRows(value = []) {
  const body = document.getElementById("settingsPrizeSplitBody");
  if (!body) return;
  const rows = normalizePrizeSplitRows(value);
  const finalRows = rows.length ? rows : DEFAULT_PRIZE_SPLIT_ROWS;
  body.innerHTML = finalRows
    .map(
      (row) => `
      <tr data-prize-split-row>
        <td>
          <input type="number" min="1" step="1" data-prize-place value="${row.place}" />
        </td>
        <td>
          <input type="number" min="0" step="1" data-prize-amount value="${row.amount}" />
        </td>
        <td>
          <button class="cta small ghost" type="button" data-prize-remove="true">Remove</button>
        </td>
      </tr>
    `,
    )
    .join("");
}

export function updatePrizeCurrencyCustomInputVisibility() {
  const currencySelect = document.getElementById("settingsPrizePoolCurrency");
  const customInput = document.getElementById("settingsPrizePoolCurrencyCustom");
  if (!currencySelect || !customInput) return;
  const isCustom = String(currencySelect.value || "").toUpperCase() === "CUSTOM";
  customInput.style.display = isCustom ? "" : "none";
}

function normalizeBooleanSetting(value, fallback = true) {
  if (value === undefined || value === null) return fallback;
  if (typeof value === "boolean") return value;
  if (typeof value === "number") return value !== 0;
  if (typeof value === "string") {
    const normalized = value.trim().toLowerCase();
    if (["false", "0", "no", "off"].includes(normalized)) return false;
    if (["true", "1", "yes", "on"].includes(normalized)) return true;
  }
  return Boolean(value);
}

export function applyBestOfToSettings(bestOf) {
  const upperInput = document.getElementById("settingsBestOfUpper");
  const lowerInput = document.getElementById("settingsBestOfLower");
  const quarterInput = document.getElementById("settingsBestOfQuarter");
  const semiInput = document.getElementById("settingsBestOfSemi");
  const upperFinalInput = document.getElementById("settingsBestOfUpperFinal");
  const finalInput = document.getElementById("settingsBestOfFinal");
  const finalResetInput = document.getElementById("settingsBestOfFinalReset");
  const lbSemiInput = document.getElementById("settingsBestOfLowerSemi");
  const lbFinalInput = document.getElementById("settingsBestOfLowerFinal");

  if (upperInput) upperInput.value = bestOf.upper ?? defaultBestOf.upper;
  if (lowerInput) lowerInput.value = bestOf.lower ?? defaultBestOf.lower;
  if (quarterInput)
    quarterInput.value = bestOf.quarter ?? defaultBestOf.quarter;
  if (semiInput) semiInput.value = bestOf.semi ?? defaultBestOf.semi;
  if (upperFinalInput)
    upperFinalInput.value = bestOf.upperFinal ?? defaultBestOf.upperFinal;
  if (finalInput) finalInput.value = bestOf.final ?? defaultBestOf.final;
  if (finalResetInput)
    finalResetInput.value =
      bestOf.finalReset ?? defaultBestOf.finalReset ?? defaultBestOf.final;
  if (lbSemiInput)
    lbSemiInput.value = bestOf.lowerSemi ?? defaultBestOf.lowerSemi;
  if (lbFinalInput)
    lbFinalInput.value = bestOf.lowerFinal ?? defaultBestOf.lowerFinal;
}

export function populateSettingsPanel({
  tournament,
  setMapPoolSelection,
  getDefaultMapPoolNames,
  updateSettingsDescriptionPreview,
  updateSettingsRulesPreview,
  syncFormatFieldVisibility,
}) {
  if (!tournament) return;
  const storedFormat =
    (typeof localStorage !== "undefined" &&
      localStorage.getItem("zboSettingsFormat")) ||
    "";
  const nameInput = document.getElementById("settingsNameInput");
  const slugInput = document.getElementById("settingsSlugInput");
  const descInput = document.getElementById("settingsDescriptionInput");
  const rulesInput = document.getElementById("settingsRulesInput");
  const formatSelect = document.getElementById("settingsFormatSelect");
  const maxInput = document.getElementById("settingsMaxPlayersInput");
  const startInput = document.getElementById("settingsStartInput");
  const checkInSelect = document.getElementById("settingsCheckInSelect");
  const checkInAfterStartToggle = document.getElementById(
    "settingsCheckInAfterStartToggle"
  );
  const accessSelect = document.getElementById("settingsAccessSelect");
  const visibilitySelect = document.getElementById("settingsVisibilitySelect");
  const imageInput = document.getElementById("settingsImageInput");
  const imagePreview = document.getElementById("settingsImagePreview");
  const rrBestOf = document.getElementById("settingsRoundRobinBestOf");
  const bestOf = {
    ...defaultBestOf,
    ...(tournament.bestOf || {}),
  };
  const upperInput = document.getElementById("settingsBestOfUpper");
  const lowerInput = document.getElementById("settingsBestOfLower");
  const quarterInput = document.getElementById("settingsBestOfQuarter");
  const semiInput = document.getElementById("settingsBestOfSemi");
  const upperFinalInput = document.getElementById("settingsBestOfUpperFinal");
  const finalInput = document.getElementById("settingsBestOfFinal");
  const finalResetInput = document.getElementById("settingsBestOfFinalReset");
  const lbSemiInput = document.getElementById("settingsBestOfLowerSemi");
  const lbFinalInput = document.getElementById("settingsBestOfLowerFinal");
  const grandFinalResetToggle = document.getElementById(
    "settingsGrandFinalResetToggle"
  );
  const rrGroups = document.getElementById("settingsRoundRobinGroups");
  const rrAdvance = document.getElementById("settingsRoundRobinAdvance");
  const rrPlayoffs = document.getElementById("settingsRoundRobinPlayoffs");
  const qualifyRow = document.getElementById("settingsCircuitQualifyRow");
  const qualifyInput = document.getElementById("settingsCircuitQualifyCount");
  const prizePoolTotalInput = document.getElementById("settingsPrizePoolTotal");
  const prizePoolCurrencyInput = document.getElementById(
    "settingsPrizePoolCurrency",
  );
  const prizePoolCurrencyCustomInput = document.getElementById(
    "settingsPrizePoolCurrencyCustom",
  );
  if (nameInput) nameInput.value = tournament.name || "";
  if (slugInput) slugInput.value = tournament.slug || "";
  if (descInput) descInput.value = tournament.description || "";
  if (rulesInput) rulesInput.value = tournament.rules || "";
  syncMarkdownSurfaceForInput(descInput);
  syncMarkdownSurfaceForInput(rulesInput);
  if (formatSelect)
    formatSelect.value =
      tournament.format || storedFormat || "Double Elimination";
  if (maxInput) maxInput.value = tournament.maxPlayers || "";
  if (startInput) {
    startInput.value = tournament.startTime
      ? formatLocalDateTimeInput(tournament.startTime)
      : "";
    if (startInput._flatpickr) {
      if (startInput.value) {
        startInput._flatpickr.setDate(new Date(tournament.startTime), false);
      } else {
        startInput._flatpickr.clear();
      }
    }
  }
  if (checkInSelect) {
    const total = Number(tournament.checkInWindowMinutes || 0);
    const normalized = Math.max(0, Math.min(180, Math.round(total / 15) * 15));
    checkInSelect.value = String(normalized);
  }
  if (checkInAfterStartToggle) {
    checkInAfterStartToggle.checked = normalizeBooleanSetting(
      tournament.allowCheckInAfterStart,
      false
    );
  }
  if (accessSelect) {
    accessSelect.value = tournament.isInviteOnly ? "closed" : "open";
  }
  if (visibilitySelect) {
    visibilitySelect.value =
      String(tournament.visibility || "").toLowerCase() === "private"
        ? "private"
        : "public";
  }
  if (imageInput) imageInput.value = "";
  if (imagePreview) {
    if (tournament.coverImageUrl) {
      imagePreview.src = tournament.coverImageUrl;
      imagePreview.style.display = "block";
      delete imagePreview.dataset.tempPreview;
      imagePreview.dataset.reuseUrl = tournament.coverImageUrl;
      delete imagePreview.dataset.clearCover;
    } else {
      imagePreview.removeAttribute("src");
      imagePreview.style.display = "none";
      delete imagePreview.dataset.tempPreview;
      delete imagePreview.dataset.reuseUrl;
      delete imagePreview.dataset.clearCover;
    }
  }
  const requirePulseInput = document.getElementById("settingsRequirePulseLink");
  if (requirePulseInput)
    requirePulseInput.checked = normalizeBooleanSetting(
      tournament.requirePulseLink,
      true
    );
  setMapPoolSelection(
    tournament.mapPool?.length ? tournament.mapPool : getDefaultMapPoolNames()
  );
  updateSettingsDescriptionPreview();
  updateSettingsRulesPreview();
  if (upperInput) upperInput.value = bestOf.upper ?? defaultBestOf.upper;
  if (lowerInput) lowerInput.value = bestOf.lower ?? defaultBestOf.lower;
  if (quarterInput)
    quarterInput.value = bestOf.quarter ?? defaultBestOf.quarter;
  if (semiInput) semiInput.value = bestOf.semi ?? defaultBestOf.semi;
  if (upperFinalInput)
    upperFinalInput.value = bestOf.upperFinal ?? defaultBestOf.upperFinal;
  if (finalInput) finalInput.value = bestOf.final ?? defaultBestOf.final;
  if (finalResetInput)
    finalResetInput.value =
      bestOf.finalReset ?? defaultBestOf.finalReset ?? defaultBestOf.final;
  if (lbSemiInput)
    lbSemiInput.value = bestOf.lowerSemi ?? defaultBestOf.lowerSemi;
  if (lbFinalInput)
    lbFinalInput.value = bestOf.lowerFinal ?? defaultBestOf.lowerFinal;
  if (grandFinalResetToggle) {
    grandFinalResetToggle.checked = Boolean(tournament.grandFinalReset);
  }
  const rrSettings = normalizeRoundRobinSettings(tournament.roundRobin || {});
  if (rrGroups) rrGroups.value = rrSettings.groups;
  if (rrAdvance) rrAdvance.value = rrSettings.advancePerGroup;
  if (rrPlayoffs) rrPlayoffs.value = rrSettings.playoffs;
  if (rrBestOf) rrBestOf.value = rrSettings.bestOf ?? defaultRoundRobinSettings.bestOf;

  const qualifyCount = Number(tournament.circuitQualifyCount);
  if (qualifyInput) {
    qualifyInput.value = Number.isFinite(qualifyCount) ? qualifyCount : "";
  }
  if (prizePoolTotalInput) {
    const total = Number(tournament.prizePoolTotal);
    prizePoolTotalInput.value =
      Number.isFinite(total) && total >= 0 ? String(Math.round(total)) : "";
  }
  if (prizePoolCurrencyInput) {
    const currency = String(tournament.prizePoolCurrency || "USD").toUpperCase();
    prizePoolCurrencyInput.value = currency || "USD";
  }
  if (prizePoolCurrencyCustomInput) {
    prizePoolCurrencyCustomInput.value = String(
      tournament.prizePoolCurrencyCustom || "",
    );
  }
  updatePrizeCurrencyCustomInputVisibility();
  renderPrizeSplitRows(
    normalizePrizeSplitRows(
      tournament.prizePoolSplit || [],
      Number(tournament.prizePoolTotal || 0),
    ),
  );
  if (qualifyRow) {
    qualifyRow.style.display = tournament.isCircuitFinal ? "" : "none";
  }

  applyBestOfToSettings({
    ...defaultBestOf,
    ...(tournament.bestOf || {}),
  });
  syncFormatFieldVisibility("settings");
  formatSelect?.dispatchEvent(new Event("change"));
}
